def test_modify_closed_encounter_returns_409(closed_encounter_id, clinician_auth_headers, api_client):
    payload = {"serviceType": {"text": "Updated service"}}
    resp = api_client.patch(
        f"/Encounter/{closed_encounter_id}",
        json=payload,
        headers=clinician_auth_headers,
    )
    assert resp.status_code == 409
    body = resp.json()
    assert "error" in body or "issue" in body

def test_close_already_finished_encounter_is_boundary_conflict(closed_encounter_id, clinician_auth_headers, api_client):
    resp = api_client.post(
        f"/Encounter/{closed_encounter_id}/close",
        headers=clinician_auth_headers,
    )
    assert resp.status_code in (200, 409)
    body = resp.json()
    if resp.status_code == 200:
        assert body["status"] == "finished"
    else:
        assert "error" in body or "issue" in body
